 CREATE OR REPLACE FUNCTION public.approve_beta_application(p_application_id uuid, p_admin_id uuid)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
  RETURNS jsonb                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 DECLARE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   v_user_id UUID;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
   v_current_count INTEGER;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
   v_max_beta INTEGER := 100;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
   v_beta_expires TIMESTAMPTZ := '2026-04-30 23:59:59+09'::TIMESTAMPTZ;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
 BEGIN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   -- 1. 신청 레코드 조회 + 잠금                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   SELECT user_id INTO v_user_id                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   FROM beta_applications                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
   WHERE id = p_application_id AND status = 'pending'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
   FOR UPDATE;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   IF v_user_id IS NULL THEN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
     RETURN jsonb_build_object('success', false, 'error', '유효하지 않은 신청이거나 이미 처리되었습니다');                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
   END IF;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   -- 2. 현재 승인 수 확인                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
   SELECT COUNT(*) INTO v_current_count                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
   FROM beta_applications                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
   WHERE status = 'approved';                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   IF v_current_count >= v_max_beta THEN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
     RETURN jsonb_build_object('success', false, 'error', '베타 정원(100명)이 마감되었습니다');                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
   END IF;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   -- 3. 신청 상태 업데이트                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
   UPDATE beta_applications                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
   SET status = 'approved',                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
       reviewed_by = p_admin_id,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
       reviewed_at = NOW(),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
       updated_at = NOW()                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
   WHERE id = p_application_id;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   -- 4. 크레딧 지급 (실전 플랜 동일: 모의고사 3, 스크립트 15, 튜터링 0)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   UPDATE user_credits                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   SET current_plan = 'beta',                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
       plan_mock_exam_credits = 3,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
       plan_script_credits = 15,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
       plan_tutoring_credits = 0,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
       plan_expires_at = v_beta_expires,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
       updated_at = NOW()                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
   WHERE user_id = v_user_id;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   RETURN jsonb_build_object(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
     'success', true,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
     'user_id', v_user_id::text,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
     'remaining', v_max_beta - v_current_count - 1                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
   );                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
 END;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.charge_balance(p_user_id uuid, p_amount_krw integer)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
  RETURNS integer                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 DECLARE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   v_new_balance INTEGER;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
 BEGIN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   UPDATE user_credits                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   SET balance_krw = balance_krw + p_amount_krw,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
       updated_at = NOW()                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
   WHERE user_id = p_user_id                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
   RETURNING balance_krw INTO v_new_balance;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   IF NOT FOUND THEN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
     RAISE EXCEPTION 'user_credits not found for user %', p_user_id;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
   END IF;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   RETURN v_new_balance;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
 END;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.check_balance(p_user_id uuid)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
  RETURNS integer                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
  LANGUAGE sql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
  STABLE SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
 AS $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
   SELECT COALESCE(balance_krw, 0)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
   FROM user_credits                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
   WHERE user_id = p_user_id;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.consume_mock_exam_credit(p_user_id uuid)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
  RETURNS boolean                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
 DECLARE\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
   v_plan_credits INTEGER;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
   v_credits INTEGER;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
 BEGIN\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   SELECT plan_mock_exam_credits, mock_exam_credits\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
   INTO v_plan_credits, v_credits\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   FROM user_credits\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   WHERE user_id = p_user_id\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
   FOR UPDATE;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
 \r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   -- 플랜 크레딧 먼저 차감 (만료분 우선)\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
   IF v_plan_credits > 0 THEN\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
     UPDATE user_credits\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
     SET plan_mock_exam_credits = plan_mock_exam_credits - 1,\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
         updated_at = NOW()\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
     WHERE user_id = p_user_id;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
     RETURN true;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   END IF;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 \r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   -- 횟수권 크레딧 차감 (영구)\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
   IF v_credits > 0 THEN\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
     UPDATE user_credits\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
     SET mock_exam_credits = mock_exam_credits - 1,\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
         updated_at = NOW()\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
     WHERE user_id = p_user_id;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
     RETURN true;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   END IF;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 \r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   -- 크레딧 부족\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   RETURN false;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 END;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.consume_script_credit(p_user_id uuid)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
  RETURNS boolean                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
 DECLARE\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
   v_plan_credits INTEGER;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
   v_credits INTEGER;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
 BEGIN\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   -- 현재 크레딧 조회\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   SELECT plan_script_credits, script_credits\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
   INTO v_plan_credits, v_credits\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   FROM user_credits\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   WHERE user_id = p_user_id\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
   FOR UPDATE;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
 \r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   -- 플랜 크레딧 먼저 차감\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
   IF v_plan_credits > 0 THEN\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
     UPDATE user_credits\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
     SET plan_script_credits = plan_script_credits - 1,\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
         updated_at = NOW()\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
     WHERE user_id = p_user_id;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
     RETURN true;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   END IF;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 \r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   -- 횟수권 크레딧 차감\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
   IF v_credits > 0 THEN\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
     UPDATE user_credits\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
     SET script_credits = script_credits - 1,\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
         updated_at = NOW()\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
     WHERE user_id = p_user_id;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
     RETURN true;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   END IF;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 \r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   -- 잔여 크레딧 없음\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   RETURN false;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 END;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.consume_tutoring_credit(p_user_id uuid)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
  RETURNS boolean                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
 DECLARE\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
   v_plan_credits INTEGER;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
   v_credits INTEGER;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
 BEGIN\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   SELECT plan_tutoring_credits, tutoring_credits\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   INTO v_plan_credits, v_credits\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   FROM user_credits\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   WHERE user_id = p_user_id\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
   FOR UPDATE;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
 \r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   -- 플랜 크레딧 먼저 차감 (만료분 우선)\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
   IF v_plan_credits > 0 THEN\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
     UPDATE user_credits\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
     SET plan_tutoring_credits = plan_tutoring_credits - 1,\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
         updated_at = NOW()\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
     WHERE user_id = p_user_id;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
     RETURN true;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   END IF;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 \r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   -- 횟수권 크레딧 차감 (영구)\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
   IF v_credits > 0 THEN\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
     UPDATE user_credits\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
     SET tutoring_credits = tutoring_credits - 1,\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
         updated_at = NOW()\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
     WHERE user_id = p_user_id;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
     RETURN true;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   END IF;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 \r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   -- 크레딧 부족\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   RETURN false;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 END;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.deduct_usage_cost(p_user_id uuid, p_cost_krw integer)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
  RETURNS TABLE(success boolean, remaining_balance integer)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 DECLARE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   v_current_balance INTEGER;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
 BEGIN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   -- 현재 잔액 조회 (FOR UPDATE 락)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
   SELECT balance_krw INTO v_current_balance                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
   FROM user_credits                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
   WHERE user_id = p_user_id                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
   FOR UPDATE;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   IF NOT FOUND THEN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
     RETURN QUERY SELECT false, 0;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
     RETURN;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
   END IF;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   -- 잔액 부족 확인                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
   IF v_current_balance < p_cost_krw THEN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
     RETURN QUERY SELECT false, v_current_balance;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
     RETURN;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
   END IF;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   -- 차감                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
   UPDATE user_credits                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   SET balance_krw = balance_krw - p_cost_krw,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
       updated_at = NOW()                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
   WHERE user_id = p_user_id;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   RETURN QUERY SELECT true, (v_current_balance - p_cost_krw);                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 END;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.expire_beta_plans()                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
  RETURNS integer                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 DECLARE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   v_count INTEGER;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
 BEGIN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   UPDATE user_credits                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   SET current_plan = 'free',                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
       plan_mock_exam_credits = 0,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
       plan_script_credits = 0,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
       plan_tutoring_credits = 0,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
       plan_expires_at = NULL,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
       updated_at = NOW()                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
   WHERE current_plan = 'beta'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
     AND (plan_expires_at IS NULL OR plan_expires_at < NOW());                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   GET DIAGNOSTICS v_count = ROW_COUNT;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
   RETURN v_count;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 END;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.get_beta_stats()                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
  RETURNS jsonb                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 DECLARE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   v_total INTEGER;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   v_approved INTEGER;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   v_pending INTEGER;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
   v_rejected INTEGER;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
 BEGIN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   SELECT COUNT(*) INTO v_total FROM beta_applications;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
   SELECT COUNT(*) INTO v_approved FROM beta_applications WHERE status = 'approved';                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
   SELECT COUNT(*) INTO v_pending FROM beta_applications WHERE status = 'pending';                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
   SELECT COUNT(*) INTO v_rejected FROM beta_applications WHERE status = 'rejected';                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   RETURN jsonb_build_object(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
     'total', v_total,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
     'approved', v_approved,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
     'pending', v_pending,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
     'rejected', v_rejected,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
     'remaining', 100 - v_approved                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
   );                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
 END;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.get_dau_count(target_date date)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  RETURNS TABLE(count bigint)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
  LANGUAGE sql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   SELECT COUNT(*)::BIGINT\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
   FROM auth.users\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
   WHERE last_sign_in_at::date = target_date;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.get_user_cost_summary(p_user_id uuid, p_from timestamp with time zone DEFAULT (now() - '30 days'::interval), p_to timestamp with time zone DEFAULT now())                                                                                                                                                                                                                                                                                                                                                                                                         +
  RETURNS TABLE(session_type text, total_calls bigint, total_cost_usd numeric, total_cost_krw numeric)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
  LANGUAGE sql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
  STABLE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
 AS $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
   SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
     session_type,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
     COUNT(*) AS total_calls,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
     SUM(cost_usd) AS total_cost_usd,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
     ROUND(SUM(cost_usd) * 1400, 0) AS total_cost_krw                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
   FROM api_usage_logs                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   WHERE user_id = p_user_id                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
     AND created_at >= p_from                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
     AND created_at < p_to                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
   GROUP BY session_type                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   ORDER BY total_cost_krw DESC;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.get_user_usage_summary(p_user_id uuid, p_from timestamp with time zone DEFAULT (now() - '30 days'::interval), p_to timestamp with time zone DEFAULT now())                                                                                                                                                                                                                                                                                                                                                                                                        +
  RETURNS TABLE(session_type text, feature text, call_count bigint, total_cost_usd numeric, total_tokens_in bigint, total_tokens_out bigint, total_audio_sec numeric)                                                                                                                                                                                                                                                                                                                                                                                                                                +
  LANGUAGE sql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
  STABLE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
 AS $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
   SELECT                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
     session_type,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
     feature,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
     COUNT(*) AS call_count,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
     SUM(cost_usd) AS total_cost_usd,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
     SUM(tokens_in) AS total_tokens_in,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
     SUM(tokens_out) AS total_tokens_out,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
     SUM(audio_duration_sec) AS total_audio_sec                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
   FROM api_usage_logs                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   WHERE user_id = p_user_id                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
     AND created_at >= p_from                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
     AND created_at < p_to                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
   GROUP BY session_type, feature                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
   ORDER BY total_cost_usd DESC;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.handle_new_user()                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
  RETURNS trigger                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SET search_path TO ''                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
 AS $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 BEGIN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   INSERT INTO public.profiles (id, email)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
   VALUES (NEW.id, NEW.email)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
   ON CONFLICT (id) DO NOTHING;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
   RETURN NEW;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 END;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.handle_new_user_credits()                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
  RETURNS trigger                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SET search_path TO ''                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
 AS $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 BEGIN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   INSERT INTO public.user_credits (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
     user_id, current_plan,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
     plan_mock_exam_credits, plan_script_credits,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
     mock_exam_credits, script_credits                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   )                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
   VALUES (NEW.id, 'free', 0, 0, 0, 0)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   ON CONFLICT (user_id) DO NOTHING;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
   RETURN NEW;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 END;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.handle_new_user_polar_balance()                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  RETURNS trigger                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
