 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.increment_completed_prescriptions(p_session_id uuid)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
  RETURNS void                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 BEGIN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   UPDATE tutoring_sessions                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
   SET completed_prescriptions = completed_prescriptions + 1                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
   WHERE id = p_session_id;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 END;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.increment_script_credits(p_user_id uuid, p_amount integer)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
  RETURNS void                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
 BEGIN\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   UPDATE user_credits\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   SET script_credits = script_credits + p_amount,\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
       updated_at = NOW()\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
   WHERE user_id = p_user_id;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
 END;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.increment_training_count(p_prescription_id uuid)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
  RETURNS void                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 BEGIN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   UPDATE tutoring_prescriptions                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   SET training_count = training_count + 1                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
