 END;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.polar_admin_adjust_balance(p_user_id uuid, p_amount integer, p_description text DEFAULT '관리자 조정'::text)                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
  RETURNS jsonb                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 DECLARE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   v_new_balance INTEGER;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
 BEGIN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   UPDATE polar_balances                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   SET balance_krw = GREATEST(balance_krw + p_amount, 0),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
       updated_at = NOW()                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
   WHERE user_id = p_user_id                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
   RETURNING balance_krw INTO v_new_balance;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   IF NOT FOUND THEN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
     RETURN jsonb_build_object('success', false, 'error', 'no_balance');                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   END IF;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   -- 이력 기록                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
   INSERT INTO polar_transactions (user_id, type, amount, balance_after, description)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
   VALUES (p_user_id, 'admin_adjust', p_amount, v_new_balance, p_description);                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   RETURN jsonb_build_object('success', true, 'balance', v_new_balance);                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
 END;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.polar_charge_balance(p_user_id uuid, p_amount_krw integer, p_description text DEFAULT '크레딧 충전'::text, p_ref_id text DEFAULT NULL::text)                                                                                                                                                                                                                                                                                                                                                                                                                      +
  RETURNS jsonb                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 DECLARE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   v_new_balance INTEGER;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
 BEGIN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   -- 잔액 충전                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
   UPDATE polar_balances                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   SET balance_krw = balance_krw + p_amount_krw,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
       total_charged = total_charged + p_amount_krw,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
       updated_at = NOW()                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
   WHERE user_id = p_user_id                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
   RETURNING balance_krw INTO v_new_balance;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   IF NOT FOUND THEN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
     -- 행이 없으면 생성                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
     INSERT INTO polar_balances (user_id, balance_krw, total_charged, total_used)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
     VALUES (p_user_id, p_amount_krw, p_amount_krw, 0)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
     RETURNING balance_krw INTO v_new_balance;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
   END IF;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   -- 이력 기록                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
   INSERT INTO polar_transactions (user_id, type, amount, balance_after, description, ref_id)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
   VALUES (p_user_id, 'charge', p_amount_krw, v_new_balance, p_description, p_ref_id);                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   RETURN jsonb_build_object('success', true, 'balance', v_new_balance);                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
 END;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.polar_deduct_balance(p_user_id uuid, p_cost_krw integer, p_description text DEFAULT '크레딧 사용'::text, p_ref_id text DEFAULT NULL::text)                                                                                                                                                                                                                                                                                                                                                                                                                        +
  RETURNS jsonb                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 DECLARE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   v_current_balance INTEGER;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
   v_new_balance INTEGER;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
 BEGIN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   -- 현재 잔액 조회 (FOR UPDATE 락)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
   SELECT balance_krw INTO v_current_balance                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
   FROM polar_balances                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   WHERE user_id = p_user_id                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
   FOR UPDATE;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   IF NOT FOUND THEN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
     RETURN jsonb_build_object('success', false, 'error', 'no_balance', 'balance', 0);                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   END IF;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   -- 잔액 부족                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
   IF v_current_balance < p_cost_krw THEN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
     RETURN jsonb_build_object('success', false, 'error', 'insufficient', 'balance', v_current_balance);                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   END IF;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   -- 차감                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
   v_new_balance := v_current_balance - p_cost_krw;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   UPDATE polar_balances                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   SET balance_krw = v_new_balance,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
       total_used = total_used + p_cost_krw,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
       updated_at = NOW()                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
   WHERE user_id = p_user_id;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   -- 이력 기록                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
   INSERT INTO polar_transactions (user_id, type, amount, balance_after, description, ref_id)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
   VALUES (p_user_id, 'usage', -p_cost_krw, v_new_balance, p_description, p_ref_id);                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   RETURN jsonb_build_object('success', true, 'balance', v_new_balance);                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
 END;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.polar_get_balance(p_user_id uuid)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
  RETURNS integer                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
  LANGUAGE sql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
  STABLE SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
 AS $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
   SELECT COALESCE(balance_krw, 0)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
   FROM polar_balances                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   WHERE user_id = p_user_id;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.polar_refund_balance(p_user_id uuid, p_amount_krw integer, p_description text DEFAULT '크레딧 환불'::text, p_ref_id text DEFAULT NULL::text)                                                                                                                                                                                                                                                                                                                                                                                                                      +
  RETURNS jsonb                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 DECLARE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   v_new_balance INTEGER;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
 BEGIN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   UPDATE polar_balances                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   SET balance_krw = balance_krw + p_amount_krw,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
       total_used = GREATEST(total_used - p_amount_krw, 0),                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
       updated_at = NOW()                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
   WHERE user_id = p_user_id                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
   RETURNING balance_krw INTO v_new_balance;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   IF NOT FOUND THEN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
     RETURN jsonb_build_object('success', false, 'error', 'no_balance');                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   END IF;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   -- 이력 기록                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
   INSERT INTO polar_transactions (user_id, type, amount, balance_after, description, ref_id)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
   VALUES (p_user_id, 'refund', p_amount_krw, v_new_balance, p_description, p_ref_id);                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   RETURN jsonb_build_object('success', true, 'balance', v_new_balance);                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
 END;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.process_payment(p_user_id uuid, p_payment_id text, p_product_id text, p_order_name text, p_amount integer, p_pg_provider text DEFAULT NULL::text, p_pg_tx_id text DEFAULT NULL::text, p_pay_method text DEFAULT NULL::text, p_paid_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_receipt_url text DEFAULT NULL::text, p_is_plan boolean DEFAULT false, p_plan text DEFAULT 'free'::text, p_plan_months integer DEFAULT 0, p_mock_exam_credits integer DEFAULT 0, p_script_credits integer DEFAULT 0, p_tutoring_credits integer DEFAULT 0)+
  RETURNS jsonb                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
 DECLARE\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
   v_order_id UUID;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
   v_expires_at TIMESTAMPTZ;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 BEGIN\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   -- 원자적 INSERT (UNIQUE INDEX idx_orders_payment_id로 중복 방지)\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   INSERT INTO orders (\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
     user_id, product_id, order_name, amount, status,\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
     payment_id, pg_provider, pg_tx_id, pay_method, paid_at, receipt_url\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
   ) VALUES (\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
     p_user_id, p_product_id, p_order_name, p_amount, 'paid',\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
     p_payment_id, p_pg_provider, p_pg_tx_id, p_pay_method,\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
     COALESCE(p_paid_at, NOW()), p_receipt_url\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   )\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   ON CONFLICT (payment_id) DO NOTHING\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   RETURNING id INTO v_order_id;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 \r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   -- 이미 처리된 결제면 크레딧 지급 건너뛰기 (멱등성)\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   IF v_order_id IS NULL THEN\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
     RETURN jsonb_build_object('success', true, 'duplicate', true);\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
   END IF;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 \r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   -- 크레딧 지급\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   IF p_is_plan THEN\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
     -- 플랜 상품: 플랜 크레딧 설정 + 만료일 설정\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
     v_expires_at := NOW() + (p_plan_months || ' months')::INTERVAL;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
     UPDATE user_credits SET\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
       current_plan = p_plan,\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
       plan_mock_exam_credits = p_mock_exam_credits,\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
       plan_script_credits = p_script_credits,\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
       plan_tutoring_credits = p_tutoring_credits,\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
       plan_expires_at = v_expires_at,\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
       updated_at = NOW()\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
     WHERE user_id = p_user_id;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
   ELSE\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
     -- 횟수권: 영구 크레딧 누적\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
     UPDATE user_credits SET\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
       mock_exam_credits = mock_exam_credits + p_mock_exam_credits,\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
       script_credits = script_credits + p_script_credits,\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
       tutoring_credits = tutoring_credits + p_tutoring_credits,\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
       updated_at = NOW()\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
     WHERE user_id = p_user_id;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
   END IF;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
 \r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   RETURN jsonb_build_object('success', true, 'order_id', v_order_id::text);\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 END;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.process_polar_payment(p_user_id uuid, p_polar_checkout_id text, p_polar_product_id text, p_product_type text, p_amount integer, p_credit_amount integer)                                                                                                                                                                                                                                                                                                                                                                                                          +
  RETURNS jsonb                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 DECLARE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   v_order_id UUID;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   v_new_balance INTEGER;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
 BEGIN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   -- 멱등성: polar_checkout_id 중복 방지                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
   INSERT INTO polar_orders (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
     user_id, polar_checkout_id, polar_product_id,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
     product_type, amount, credit_amount, status                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   ) VALUES (                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
     p_user_id, p_polar_checkout_id, p_polar_product_id,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
     p_product_type, p_amount, p_credit_amount, 'paid'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   )                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 +
   ON CONFLICT (polar_checkout_id) DO NOTHING                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
   RETURNING id INTO v_order_id;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   -- 이미 처리된 결제                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   IF v_order_id IS NULL THEN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
     RETURN jsonb_build_object('success', true, 'duplicate', true);                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   END IF;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   -- 크레딧 지급 (후원만 상품은 0)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
   IF p_credit_amount > 0 THEN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
     SELECT (polar_charge_balance(p_user_id, p_credit_amount, '크레딧 충전', p_polar_checkout_id))->>'balance'                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
     INTO v_new_balance;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   END IF;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   RETURN jsonb_build_object(                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
     'success', true,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
     'order_id', v_order_id::text,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
     'balance', COALESCE(v_new_balance, 0)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
   );                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
 END;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.refund_mock_exam_credit(p_user_id uuid)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
  RETURNS void                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
 BEGIN\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   -- 횟수권 크레딧으로 환불 (영구)\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
   UPDATE user_credits\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   SET mock_exam_credits = mock_exam_credits + 1,\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  +
       updated_at = NOW()\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
   WHERE user_id = p_user_id;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
 END;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.refund_script_credit(p_user_id uuid)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
  RETURNS void                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
 BEGIN\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   -- 횟수권 크레딧으로 환불 (영구)\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
   UPDATE user_credits\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   SET script_credits = script_credits + 1,\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        +
       updated_at = NOW()\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
   WHERE user_id = p_user_id;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
 END;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.refund_tutoring_credit(p_user_id uuid)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
  RETURNS void                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
 BEGIN\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   -- 횟수권 크레딧으로 환불 (영구)\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
   UPDATE user_credits\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   SET tutoring_credits = tutoring_credits + 1,\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
       updated_at = NOW()\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
   WHERE user_id = p_user_id;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      +
 END;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.refund_usage_cost(p_user_id uuid, p_cost_krw integer)                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
  RETURNS integer                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
  SECURITY DEFINER                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 DECLARE                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   v_new_balance INTEGER;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
 BEGIN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   UPDATE user_credits                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   SET balance_krw = balance_krw + p_cost_krw,                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
       updated_at = NOW()                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            +
   WHERE user_id = p_user_id                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
   RETURNING balance_krw INTO v_new_balance;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
   RETURN COALESCE(v_new_balance, 0);                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
 END;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.update_beta_applications_updated_at()                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
  RETURNS trigger                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 BEGIN                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
   NEW.updated_at = NOW();                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           +
   RETURN NEW;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       +
 END;                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 
 CREATE OR REPLACE FUNCTION public.update_updated_at()                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               +
  RETURNS trigger                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    +
  LANGUAGE plpgsql                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   +
 AS $function$\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
 BEGIN\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             +
   NEW.updated_at = NOW();\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         +
   RETURN NEW;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     +
 END;\r                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              +
 $function$                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          +
 

